solution_code:
#define N 3

float calculate_edf_utilization(float exec[], float period[], int n) {
    float total = 0.0f;
    for (int i = 0; i < n; i++) {
        total += exec[i] / period[i];
    }
    return total;
}

validation.test_code:
void test_calculate_edf_single(void) {
    float exec[] = {2.0f};
    float period[] = {5.0f};
    float result = calculate_edf_utilization(exec, period, 1);
    TEST_ASSERT_EQUAL_INT(0, (int)(result * 100));
}

void test_calculate_edf_below_threshold(void) {
    float exec[] = {3.0f, 1.0f, 2.0f};
    float period[] = {20.0f, 5.0f, 10.0f};
    float result = calculate_edf_utilization(exec, period, 3);
    /* 0.15 + 0.20 + 0.20 = 0.55 */
    TEST_ASSERT_EQUAL_INT(55, (int)(result * 100));
}

void test_calculate_edf_at_threshold(void) {
    float exec[] = {1.0f, 1.0f};
    float period[] = {2.0f, 2.0f};
    float result = calculate_edf_utilization(exec, period, 2);
    /* 0.5 + 0.5 = 1.0 */
    TEST_ASSERT_EQUAL_INT(100, (int)(result * 100));
}

void test_calculate_edf_over_threshold(void) {
    float exec[] = {3.0f, 2.0f};
    float period[] = {4.0f, 4.0f};
    float result = calculate_edf_utilization(exec, period, 2);
    /* 0.75 + 0.5 = 1.25 */
    TEST_ASSERT_EQUAL_INT(125, (int)(result * 100));
}

int main(void) {
    RUN_TEST(test_calculate_edf_single);
    RUN_TEST(test_calculate_edf_below_threshold);
    RUN_TEST(test_calculate_edf_at_threshold);
    RUN_TEST(test_calculate_edf_over_threshold);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}
